framework_css:
/*
  Life Coach Site Framework Styles
  Matches modern, confident SaaS-like life coaching aesthetic.
*/

:root {
    /* Color Palette */
    --color-primary-900: #003845; /* Deep teal background */
    --color-primary-700: #046C5B; /* Secondary teal */
    --color-primary-600: #0F8F6C; /* Hover teal */
    --color-primary-500: #22C58E; /* Brand green (CTA) */
    --color-accent-400: #30E3CA; /* Accent turquoise */

    --color-neutral-000: #FFFFFF;
    --color-neutral-050: #F3F6F8;
    --color-neutral-500: #7A8B96;

    --color-success: #22C58E;
    --color-error: #E4505A;
    --color-warning: #F5A623;
    --color-info: #2D9CDB;

    /* Typography */
    --font-heading: 'Space Grotesk', 'Helvetica', sans-serif;
    --font-body: 'Source Sans 3', 'Arial', sans-serif;

    --fs-h1: 3.25rem; /* 52px */
    --fs-h2: 2.25rem; /* 36px */
    --fs-h3: 1.5rem;  /* 24px */
    --fs-body: 1rem;  /* 16px */
    --fs-small: 0.875rem; /* 14px */

    --fw-light: 300;
    --fw-regular: 400;
    --fw-medium: 500;
    --fw-semibold: 600;
    --fw-bold: 700;

    --lh-tight: 1.2;
    --lh-normal: 1.5;
    --lh-relaxed: 1.7;

    /* Spacing scale (base = 8px) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout */
    --layout-max-width: 1120px;
    --header-height: 80px;

    /* UI */
    --radius-sm: 4px;
    --radius-md: 8px;
    --radius-pill: 999px;

    --shadow-soft: 0 10px 30px rgba(0, 0, 0, 0.12);
    --shadow-subtle: 0 2px 8px rgba(0, 0, 0, 0.08);

    --transition-fast: 160ms ease-out;
    --transition-med: 220ms ease-out;
}

/* Global Reset & Base */
* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body.page {
    font-family: var(--font-body);
    font-size: var(--fs-body);
    line-height: var(--lh-normal);
    color: var(--color-neutral-000);
    background-color: var(--color-primary-900);
    -webkit-font-smoothing: antialiased;
}

.page-shell {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    /* Subtle circular lines inspired by hero background */
    background-image:
        radial-gradient(circle at -10% 110%, rgba(0, 70, 80, 0.9) 0, rgba(0, 70, 80, 0.9) 320px, transparent 320px),
        radial-gradient(circle at 110% -10%, rgba(0, 70, 80, 0.9) 0, rgba(0, 70, 80, 0.9) 320px, transparent 320px);
}

img {
    max-width: 100%;
    display: block;
}

.container {
    width: 100%;
    max-width: var(--layout-max-width);
    margin: 0 auto;
    padding: 0 var(--space-3);
}

h1,
 h2,
 h3,
 h4,
 h5,
 h6 {
    margin: 0;
    font-family: var(--font-heading);
    font-weight: var(--fw-semibold);
    color: var(--color-neutral-000);
}

p {
    margin: 0;
}

a {
    color: inherit;
    text-decoration: none;
}

a:focus-visible,
button:focus-visible {
    outline: 2px solid var(--color-accent-400);
    outline-offset: 2px;
}

/* Header */

.site-header {
    position: sticky;
    top: 0;
    z-index: 20;
    background-color: var(--color-primary-900);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: var(--header-height);
}

.brand {
    display: inline-flex;
    align-items: center;
    gap: var(--space-1);
    color: var(--color-neutral-000);
}

.brand-mark {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 2px solid var(--color-accent-400);
    position: relative;
}

.brand-mark::before,
.brand-mark::after {
    content: '';
    position: absolute;
    border-radius: 50%;
}

.brand-mark::before {
    inset: 6px;
    border: 2px solid var(--color-accent-400);
    opacity: 0.7;
}

.brand-mark::after {
    width: 14px;
    height: 14px;
    border: 2px solid var(--color-accent-400);
    border-top-color: transparent;
    border-left-color: transparent;
    transform: translate(11px, 11px) rotate(45deg);
}

.brand-text {
    font-family: var(--font-heading);
    font-weight: var(--fw-semibold);
    font-size: 1.05rem;
    letter-spacing: 0.02em;
}

.primary-nav {
    display: flex;
    align-items: center;
    gap: var(--space-3);
    font-family: var(--font-body);
    font-size: 0.95rem;
}

.nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    gap: var(--space-3);
}

.nav-main {
    margin-right: var(--space-4);
}

.nav-actions {
    gap: var(--space-2);
}

.nav-item {
    position: relative;
}

.nav-link {
    color: var(--color-neutral-000);
    font-weight: var(--fw-medium);
    letter-spacing: 0.02em;
    padding: 4px 0;
    transition: color var(--transition-fast), opacity var(--transition-fast);
    opacity: 0.9;
}

.nav-link::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    bottom: -6px;
    height: 2px;
    border-radius: 999px;
    background-color: var(--color-accent-400);
    transform-origin: center;
    transform: scaleX(0);
    transition: transform var(--transition-med);
}

.nav-link:hover {
    color: var(--color-accent-400);
    opacity: 1;
}

.nav-link:hover::after {
    transform: scaleX(1);
}

.nav-item-cta .nav-link::after {
    display: none;
}

.nav-cta {
    padding: 0.6rem 1.6rem;
    border-radius: var(--radius-pill);
    background-color: var(--color-primary-500);
    color: var(--color-primary-900);
    font-weight: var(--fw-semibold);
    box-shadow: var(--shadow-subtle);
    transition: background-color var(--transition-med), transform var(--transition-med), box-shadow var(--transition-med), color var(--transition-med);
}

.nav-cta:hover {
    background-color: var(--color-accent-400);
    color: var(--color-primary-900);
    transform: translateY(-1px);
    box-shadow: var(--shadow-soft);
}

/* Main layout */

.site-main {
    flex: 1 0 auto;
    padding-top: var(--space-6);
    padding-bottom: var(--space-6);
}

.main-inner {
    /* The main content area is intentionally left visually light
       so individual pages can define their own hero/sections. */
    min-height: 240px;
}

/* Footer */

.site-footer {
    margin-top: auto;
    background-color: var(--color-primary-900);
    border-top: 1px solid rgba(255, 255, 255, 0.06);
    color: var(--color-neutral-000);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    gap: var(--space-4);
    padding-top: var(--space-5);
    padding-bottom: var(--space-4);
}

.footer-brand {
    display: flex;
    align-items: flex-start;
    gap: var(--space-2);
    max-width: 320px;
}

.footer-brand-mark-wrapper {
    padding-top: 4px;
}

.footer-brand-text .brand-text {
    display: block;
    margin-bottom: var(--space-1);
}

.footer-tagline {
    font-size: var(--fs-small);
    color: var(--color-neutral-500);
    line-height: var(--lh-relaxed);
}

.footer-nav {
    flex: 1 1 260px;
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: var(--space-1) var(--space-4);
}

.footer-item {
    min-width: 0;
}

.footer-link {
    display: inline-block;
    font-size: var(--fs-small);
    color: var(--color-neutral-500);
    padding: 2px 0;
    transition: color var(--transition-fast), opacity var(--transition-fast);
}

.footer-link:hover {
    color: var(--color-accent-400);
    opacity: 1;
}

.footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.footer-bottom-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.footer-copy {
    font-size: 0.8rem;
    color: var(--color-neutral-500);
}

/* Utility classes (optional for pages to use) */

.text-muted {
    color: var(--color-neutral-500);
}

.bg-surface {
    background-color: var(--color-neutral-000);
}

.card {
    background-color: var(--color-neutral-000);
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-subtle);
    padding: var(--space-3);
}

@media (max-width: 960px) {
    .header-inner {
        align-items: flex-start;
        flex-direction: column;
        justify-content: center;
        padding-top: var(--space-2);
        padding-bottom: var(--space-2);
        height: auto;
        gap: var(--space-2);
    }

    .primary-nav {
        width: 100%;
        justify-content: space-between;
        column-gap: var(--space-2);
        row-gap: var(--space-1);
        flex-wrap: wrap;
    }

    .nav-main {
        flex-wrap: wrap;
        margin-right: 0;
    }

    .nav-actions {
        flex-wrap: wrap;
    }

    .nav-cta {
        padding-inline: 1.2rem;
    }

    .footer-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .footer-bottom-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-1);
    }
}

@media (max-width: 600px) {
    .container {
        padding-inline: var(--space-2);
    }

    .primary-nav {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav-list {
        flex-wrap: wrap;
    }

    .nav-main,
    .nav-actions {
        margin-right: 0;
        gap: var(--space-2);
    }
}
